from agent import *from models.products import *import simplejsonXCAT = ['New', 'Collections', 'Corporate Enquiries', 'Inspiration']def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.queue(Request('https://brabantia.com.au/', force_charset='utf-8'), process_frontpage, {})def process_frontpage(data, context, session):    strip_namespace(data)    cats1 = data.xpath('//ul[@class="navPages-list navPages-list-depth-max"]/li')    for cat1 in cats1:        name1 = cat1.xpath('a/span/text()').string()        url = cat1.xpath('a/@href').string()        if name1 not in XCAT:            cats2 = cat1.xpath('div/ul/li')            if not cats2:                session.queue(Request(url, force_charset='utf-8'), process_prodlist, dict(cat=name1))            for cat2 in cats2:                name2 = cat2.xpath('a/span/text()').string()                if name2 not in XCAT:                    cats3 = cat2.xpath('ul/li/a')                    for cat3 in cats3:                        name3 = cat3.xpath('span/text()').string()                        url = cat3.xpath('@href').string()                        session.queue(Request(url, force_charset='utf-8'), process_prodlist, dict(cat=name1+'|'+name2+'|'+name3))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//li[@class="product"]')    for prod in prods:        prod_name = prod.xpath('.//h4/a/text()').string()        url = prod.xpath('.//h4/a/@href').string()        ssid = prod.xpath('.//@data-product-id').string()        is_revs = prod.xpath('.//p[@class="card-rating"]//span[contains(@class, "ratingFull")]')        if is_revs:            session.queue(Request(url, force_charset='utf-8'), process_product, dict(context, name=prod_name, url=url, ssid=ssid))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url, force_charset='utf-8'), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.manufacturer = 'Brabantia'    product.url = context['url']    product.category = context['cat']    product.ssid = context['ssid']    prod_data = data.xpath('//script[contains(., "product_attributes")]/text()').string()    if prod_data:        prod_data = prod_data.split(" = ")[-1].strip(' ;')        if prod_data:            product_json = simplejson.loads(prod_data).get('product_attributes', {})            product.sku = product_json.get('sku')            ean = product_json.get('gtin')            if not ean:                ean = product_json.get('upc')            if ean:                product.properties.append(ProductProperty(type='id.ean', value=str(ean)))            mpn = product_json.get('mpn')            if mpn:                product.properties.append(ProductProperty(type='id.manufacturer', value=mpn))    revs = data.xpath('//li[@class="productReview"]')    for rev in revs:        review = Review()        review.url = product.url        review.type = "user"        review.title = rev.xpath('.//h5[@class="productReview-title"]/text()').string()        date = rev.xpath('.//p[@class="productReview-author"]/text()').string()        if date:            review.date = date.split('on ')[-1]        author = rev.xpath('.//p[@class="productReview-author"]/text()').string()        if author:            author = author.split(' on ')[0].split('Posted by')[-1].strip()            review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath('.//span[@itemprop="ratingValue"]/text()').string()        if grade_overall:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0))        excerpt = rev.xpath('.//p[@itemprop="reviewBody"]/text()').string(multiple=True)        if excerpt:            excerpt = excerpt.replace('&#039;', "'").replace('&', '&')            review.properties.append(ReviewProperty(type="excerpt", value=excerpt))            review.ssid = review.digest() if author else review.digest(excerpt)            product.reviews.append(review)    if product.reviews:        session.emit(product)    # no next page